(window.webpackJsonp=window.webpackJsonp||[]).push([[41],{668:function(n,t){n.exports="\x3c!-- \ntitle: Nginx\nsort: \n--\x3e \n\n# Nginx入门\n\n> [OpenResty](http://openresty.org/cn/)\n\n## 安装\n\n```yml\n# docker-compose\nversion: '3.1'\nservices:\n  nginx:\n    restart: always\n    image: nginx\n    container_name: nginx\n    ports:\n      - 80:80\n    volumes: \n      - /opt/docker_nginx/conf.d:/etc/nginx/conf.d\n      - /usr/share/nginx/html\n```\n\n## 默认\n\n```nginx\n# /etc/nginx/sites-enable/default\n\nserver {\n\tlisten 80;\n    server_name localhost;\n\n\tlocation / {\n\t\troot /var/www/html;\n\t\tindex index.html index.htm index.nginx-debian.html;\n\t}\n}\ninclude\t<someconfig>\n\nnginx -s reload\n```\n\n### 路径映射\n\n```nginx\n# = 匹配\nlocation = / {\n    # 精确匹配，不能带任何字符串\n}\n# 通用匹配\nlocation /xx {\n\t# 匹配所有/xx/的路径\n}\n# 正则匹配\nlocation ~/xx {\n    # 匹配所有以/xx开头的路径\n}\nlocation ~* \\. (git|jpg|png)$ {\n    # 匹配大多数图片格式\n}\n```\n\n## 实例\n\n### 反向代理\n\n```nginx\nlocation /test {\n\t# 反向代理\n\tproxy_pass http://group1/;\n}\n```\n\n### 文件服务器\n\n```nginx\nlocation /app {\n    # 遍历目录\n    autoindex on;\n    # 文件大小显示\n    autoindex_exact_size off;\n    # 显示服务器时间\n    autoindex_localtime on;\n    # 中文文件夹转码\n    charset utf-8;\n}\n\nautoindex on;\nautoindex_exact_size off;\nautoindex_localtime on;\ncharset utf-8;\n```\n\n### 负载均衡\n\n> 轮询\n>\n> 权重\n>\n> iphash\n\n```nginx\n# 负载均衡 权重\nupstream group1{\n   \tserver 192.168.0.1:80 weight=2;\n    server 192.168.0.1:8080 weight=1;\n}\n\nserver{\n    location /test/ {\n        # 随机重定向到两个网页\n\t\tproxy_pass http://group1/;\n  }\n}\n```\n\n"}}]);